// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Execute the aliyun command securely without invoking a shell
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunOut, aliyunErr bytes.Buffer
	aliyunCmd.Stdout = &aliyunOut
	aliyunCmd.Stderr = &aliyunErr

	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunErr.String())
	}

	// Execute the jq command, passing the output of the aliyun command as stdin
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = &aliyunOut
	var jqOut, jqErr bytes.Buffer
	jqCmd.Stdout = &jqOut
	jqCmd.Stderr = &jqErr

	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqErr.String())
	}

	outputStr := jqOut.String()

	// Write the processed output to the specified file
	if err := os.WriteFile(outputFile, jqOut.Bytes(), 0644); err != nil {
		return outputStr, fmt.Errorf("failed to write output file: %w", err)
	}

	return outputStr, nil
}

