// QuerySLBAndExport queries SLB information, formats it using jq, and exports it to a file.
// It executes the pipeline using the system shell to handle pipes and file redirection.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Construct the shell pipeline string.
	// %q is used to safely double-quote the user-provided parameters (loadBalancerName and outputFile)
	// to handle potential spaces and prevent basic shell injection.
	pipeline := fmt.Sprintf("aliyun slb DescribeLoadBalancers --LoadBalancerName %q | jq '.LoadBalancers.LoadBalancer[]' > %q", loadBalancerName, outputFile)

	// Execute the command pipeline using the standard shell ("sh -c")
	cmd := exec.Command("sh", "-c", pipeline)

	// Capture both standard output and standard error
	output, err := cmd.CombinedOutput()
	if err != nil {
		// Return the captured output along with the error for easier debugging
		return string(output), fmt.Errorf("command execution failed: %w", err)
	}

	// Return the execution result (which might be empty if stdout/stderr are fully redirected and successful)
	return string(output), nil
}

func main() {
	// Example usage of the QuerySLBAndExport function
	loadBalancerName := "my-test-slb"
	outputFile := "output.json"

	fmt.Printf("Executing query for SLB: %s\n", loadBalancerName)

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error: %v\nCommand Output: %s\n", err, result)
		return
	}

	fmt.Printf("Command executed successfully.\nCommand Output: %s\nData successfully exported to %s\n", result, outputFile)
}

