// QuerySLBAndExport executes the aliyun CLI to query SLB info, pipes it to jq, and writes the output to a file.
// This is the Go-native, shell-injection-safe equivalent of:
// aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Prepare the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Prepare the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Create the destination output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// 4. Create a pipe to connect aliyunCmd's Stdout to jqCmd's Stdin
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}

	// 5. Redirect jqCmd's Stdout to the output file
	jqCmd.Stdout = outFile

	// 6. Capture Stderr for both commands to provide meaningful error messages
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// 7. Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// 8. Wait for the aliyun command to finish and close the pipe
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// 9. Wait for the jq command to finish processing the piped data
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	return fmt.Sprintf("Successfully exported SLB info for '%s' to '%s'", loadBalancerName, outputFile), nil
}

func main() {
	// Example usage
	// Ensure that 'aliyun' CLI and 'jq' are installed and configured in your environment before running.

