// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Execute the aliyun command
	// By passing arguments directly to exec.Command rather than using "sh -c", 
	// we completely eliminate the risk of shell injection.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	var aliyunStdout bytes.Buffer
	var aliyunStderr bytes.Buffer
	cmdAliyun.Stdout = &aliyunStdout
	cmdAliyun.Stderr = &aliyunStderr

	if err := cmdAliyun.Run(); err != nil {
		return aliyunStderr.String(), fmt.Errorf("aliyun command failed: %w, output: %s", err, aliyunStderr.String())
	}

	// 2. Execute the jq command
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	// Pipe the stdout from the aliyun command into jq's stdin
	cmdJq.Stdin = &aliyunStdout

	var jqStderr bytes.Buffer
	cmdJq.Stderr = &jqStderr

	// 3. Open the output file securely
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Capture jq stdout to a buffer (to return it) and write to the file simultaneously
	var jqStdout bytes.Buffer
	cmdJq.Stdout = io.MultiWriter(file, &jqStdout)

	if err := cmdJq.Run(); err != nil {
		return jqStderr.String(), fmt.Errorf("jq command failed: %w, output: %s", err, jqStderr.String())
	}

	// Return the captured stdout on success
	return jqStdout.String(), nil
}

