// QuerySLBAndExport executes the aliyun CLI to query SLB info, pipes the output to jq,
// and redirects the final formatted output to the specified file.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Prepare the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Prepare the jq command
	// Note: In bash we use single quotes to prevent shell evaluation ('.LoadBalancers.LoadBalancer[]').
	// In Go's os/exec, we pass the argument directly without the surrounding single quotes.
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Create or truncate the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// 4. Wire the pipeline: aliyun stdout -> jq stdin
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun cmd: %w", err)
	}
	jqCmd.Stdin = pipe

	// 5. Wire jq stdout -> output file
	jqCmd.Stdout = outFile

	// 6. Capture stderr for both commands for better error reporting
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// 7. Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// 8. Wait for commands to finish in the correct order
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	return fmt.Sprintf("Successfully exported SLB information to %s", outputFile), nil
}

func main() {
	// Example usage
	// Ensure you have configured aliyun CLI and have jq installed in your system PATH.

	if len(os.Args) < 3 {
		fmt.Printf("Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		fmt.Printf("Example: %s my-slb-instance output.json\n", os.Args[0])
		return
	}

	lbName := os.Args[1]
	outFile := os.Args[2]

	result, err := QuerySLBAndExport(lbName, outFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error executing pipeline: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

