	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}
	cmdJq.Stdin = pipe

	// 4. Open the output file to redirect cmdJq's Stdout (simulating the '>' operator)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer outFile.Close()
	cmdJq.Stdout = outFile

	// 5. Capture Stderr for both commands to provide meaningful error messages
	var stderrAliyun, stderrJq bytes.Buffer
	cmdAliyun.Stderr = &stderrAliyun
