	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	jqCmd.Stdin = pipe

	// Open the output file safely using os.Create instead of shell redirection
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Use separate buffers to avoid concurrent write panics
	var aliyunErrBuf bytes.Buffer
	var jqErrBuf bytes.Buffer

	aliyunCmd.Stderr = &aliyunErrBuf
	jqCmd.Stderr = &jqErrBuf
	jqCmd.Stdout = outFile

