		outputStr := aliyunErrBuf.String() + jqErrBuf.String()
		return outputStr, fmt.Errorf("command failed: %w, output: %s", err, outputStr)
	}

	// Wait for both commands to finish
	errAliyun := aliyunCmd.Wait()
	errJq := jqCmd.Wait()

	outputStr := aliyunErrBuf.String() + jqErrBuf.String()

