// QuerySLBAndExport executes the aliyun CLI to query SLB info, pipes the output to jq,
// and writes the formatted JSON to the specified output file.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Prepare the first command: aliyun slb DescribeLoadBalancers --LoadBalancerName <NAME>
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Prepare the second command: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Create the output file where the final result will be stored
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// 4. Set up the pipe: connect the stdout of cmdAliyun to the stdin of cmdJq
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// 5. Redirect the stdout of cmdJq directly to the output file
	cmdJq.Stdout = file

	// 6. Capture stderr for both commands to provide meaningful error messages
	var aliyunStderr, jqStderr bytes.Buffer
	cmdAliyun.Stderr = &aliyunStderr
	cmdJq.Stderr = &jqStderr

	// 7. Start both commands
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, jqStderr.String())
	}

	// 8. Wait for both commands to finish
	// Waiting for cmdAliyun closes the pipe, which signals EOF to cmdJq.
	if err := cmdAliyun.Wait(); err != nil {
